package main

import (
	"encoding/xml"
	"io/ioutil"
	"log"
)

type Config struct {
	XMLName xml.Name `xmlname:"config"`
	Setting1 string   `xml:"setting1"`
	Setting2 string   `xml:"setting2"`
	// Add more settings here
}

func main() {
	data, err := ioutil.ReadFile("path/to/your/config.xml")
	if err != nil {
		log.Fatalf("error: %v", err)
	}

	var config Config
	err = xml.Unmarshal(data, &config)
	if err != nil {
		log.Fatalf("error: %v", err)
	}

	// Access the settings
	fmt.Println(config.Setting1)
	fmt.Println(config.Setting2)
	// Access more settings here
}